def find_order(n, prereqs):
    # Build the graph
    graph = {i: [] for i in range(n)}
    for b, a in prereqs:
        graph[a].append(b)

    # Initialize indegree
    indegree = [0] * n
    for a in range(n):
        for b in graph[a]:
            indegree[b] += 1

    # Initialize queue with courses with no prerequisites
    queue = [i for i in range(n) if indegree[i] == 0]

    # Topological sort
    order = []
    while queue:
        course = queue.pop(0)
        order.append(course)
        for neighbor in graph[course]:
            indegree[neighbor] -= 1
            if indegree[neighbor] == 0:
                queue.append(neighbor)

    # Check if all courses were visited
    return order if len(order) == n else []
