def min_rooms(intervals):
    if not intervals:
        return 0

    # Sort intervals by start time
    intervals.sort(key=lambda x: x[0])

    # Initialize a list to keep track of the end times of meetings
    end_times = []

    # Iterate through each interval
    for start, end in intervals:
        # If the current meeting starts before the earliest ending meeting, we need a new room
        if not end_times or start >= end_times[0]:
            end_times.append(end)
        else:
            # Otherwise, we can reuse the room of the earliest ending meeting
            end_times.pop(0)
            end_times.append(end)

    # The length of end_times is the minimum number of rooms needed
    return len(end_times)
